<?php
/**
 * inventory.php — RunMyStore.ai
 * S63: Counting Engine — enterZone + search + steppers + save
 * PART 1: Познати артикули
 * PART 2 (voice add нов артикул) = следващ commit
 */
session_start();
if (!isset($_SESSION['user_id'])) { header('Location: login.php'); exit; }
require_once 'config/database.php';
require_once 'config/config.php';
$pdo = DB::get();
$user_id=$_SESSION['user_id'];$tenant_id=$_SESSION['tenant_id'];$store_id=$_SESSION['store_id']??null;$user_role=$_SESSION['role']??'seller';$is_owner=($user_role==='owner');
$tenant=DB::run("SELECT * FROM tenants WHERE id=?",[$tenant_id])->fetch(PDO::FETCH_ASSOC);
$lang=$tenant['lang']??'bg';$currency=htmlspecialchars($tenant['currency']??'лв');
$upload_dir=__DIR__.'/uploads/zones/';if(!is_dir($upload_dir))mkdir($upload_dir,0755,true);

if(isset($_GET['ajax'])){
header('Content-Type:application/json;charset=utf-8');$ajax=$_GET['ajax'];
if($ajax==='get_zones'){echo json_encode(['ok'=>true,'zones'=>DB::run("SELECT * FROM store_zones WHERE store_id=? AND is_active=1 ORDER BY sort_order,id",[$store_id])->fetchAll(PDO::FETCH_ASSOC)]);exit;}
if($ajax==='save_zone'){$d=json_decode(file_get_contents('php://input'),true)??[];$zid=(int)($d['id']??0);$nm=trim($d['name']??'');$zt=trim($d['zone_type']??'other')?:'other';$pu=$d['photo_url']??null;$so=(int)($d['sort_order']??99);if(!$nm){echo json_encode(['ok'=>false,'error'=>'Липсва име']);exit;}if($zid>0){DB::run("UPDATE store_zones SET name=?,zone_type=?,sort_order=? WHERE id=? AND store_id=?",[$nm,$zt,$so,$zid,$store_id]);if($pu)DB::run("UPDATE store_zones SET photo_url=? WHERE id=? AND store_id=?",[$pu,$zid,$store_id]);}else{DB::run("INSERT INTO store_zones(store_id,tenant_id,name,zone_type,photo_url,sort_order)VALUES(?,?,?,?,?,?)",[$store_id,$tenant_id,$nm,$zt,$pu,$so]);$zid=(int)$pdo->lastInsertId();}echo json_encode(['ok'=>true,'id'=>$zid]);exit;}
if($ajax==='update_zone_photo'){$d=json_decode(file_get_contents('php://input'),true)??[];$zid=(int)($d['id']??0);$pu=trim($d['photo_url']??'');if(!$zid||!$pu){echo json_encode(['ok'=>false]);exit;}DB::run("UPDATE store_zones SET photo_url=? WHERE id=? AND store_id=?",[$pu,$zid,$store_id]);echo json_encode(['ok'=>true]);exit;}
if($ajax==='delete_zone'){$d=json_decode(file_get_contents('php://input'),true)??[];DB::run("UPDATE store_zones SET is_active=0 WHERE id=? AND store_id=?",[(int)($d['id']??0),$store_id]);echo json_encode(['ok'=>true]);exit;}
if($ajax==='upload_zone_photo'){if(!isset($_FILES['photo'])||$_FILES['photo']['error']!==UPLOAD_ERR_OK){echo json_encode(['ok'=>false,'error'=>'Грешка']);exit;}$f=$_FILES['photo'];$ext=strtolower(pathinfo($f['name'],PATHINFO_EXTENSION));if(!in_array($ext,['jpg','jpeg','png','webp','gif'])){echo json_encode(['ok'=>false,'error'=>'Невалиден формат']);exit;}if($f['size']>8*1024*1024){echo json_encode(['ok'=>false,'error'=>'Файлът е голям']);exit;}$fn='zone_'.$tenant_id.'_'.$store_id.'_'.time().'_'.rand(1000,9999).'.'.$ext;move_uploaded_file($f['tmp_name'],$upload_dir.$fn);echo json_encode(['ok'=>true,'url'=>'uploads/zones/'.$fn]);exit;}
if($ajax==='get_stats'){$tot=(int)DB::run("SELECT COUNT(DISTINCT p.id) FROM products p LEFT JOIN inventory i ON i.product_id=p.id AND i.store_id=? WHERE p.tenant_id=? AND p.is_active=1",[$store_id,$tenant_id])->fetchColumn();$cnt=(int)DB::run("SELECT COUNT(DISTINCT p.id) FROM products p JOIN inventory i ON i.product_id=p.id WHERE i.store_id=? AND p.tenant_id=? AND p.is_active=1 AND i.is_counted=1",[$store_id,$tenant_id])->fetchColumn();$zn=(int)DB::run("SELECT COUNT(*) FROM store_zones WHERE store_id=? AND is_active=1",[$store_id])->fetchColumn();$ss=DB::run("SELECT id,status,mode,items_counted,items_total,zones_completed,zones_total FROM inventory_count_sessions WHERE store_id=? AND status IN('in_progress','paused') ORDER BY created_at DESC LIMIT 1",[$store_id])->fetch(PDO::FETCH_ASSOC);echo json_encode(['ok'=>true,'total'=>$tot,'counted'=>$cnt,'zones'=>$zn,'session'=>$ss?:null]);exit;}
if($ajax==='start_session'){$ex=DB::run("SELECT id,status,mode,items_counted,items_total,zones_completed,zones_total FROM inventory_count_sessions WHERE store_id=? AND status IN('in_progress','paused') ORDER BY created_at DESC LIMIT 1",[$store_id])->fetch(PDO::FETCH_ASSOC);if($ex){echo json_encode(['ok'=>true,'session_id'=>(int)$ex['id'],'mode'=>$ex['mode'],'existing'=>true]);exit;}$d=json_decode(file_get_contents('php://input'),true)??[];$m=($d['mode']??'quick')==='full'?'full':'quick';$zt=(int)DB::run("SELECT COUNT(*) FROM store_zones WHERE store_id=? AND is_active=1",[$store_id])->fetchColumn();$it=(int)DB::run("SELECT COUNT(DISTINCT p.id) FROM products p LEFT JOIN inventory i ON i.product_id=p.id AND i.store_id=? WHERE p.tenant_id=? AND p.is_active=1",[$store_id,$tenant_id])->fetchColumn();DB::run("INSERT INTO inventory_count_sessions(store_id,tenant_id,status,mode,baseline_at,started_at,zones_total,items_total)VALUES(?,?,'in_progress',?,NOW(),NOW(),?,?)",[$store_id,$tenant_id,$m,$zt,$it]);echo json_encode(['ok'=>true,'session_id'=>(int)$pdo->lastInsertId(),'mode'=>$m]);exit;}

// S63: get_zone_lines
if($ajax==='get_zone_lines'){$zid=(int)($_GET['zone_id']??0);$sid=(int)($_GET['session_id']??0);if(!$zid||!$sid){echo json_encode(['ok'=>false]);exit;}$lines=DB::run("SELECT cl.product_id,cl.variation_id,cl.quantity_counted AS counted_qty,p.name,p.code,p.barcode,p.image_url,p.parent_id,p.size,p.color FROM inventory_count_lines cl JOIN products p ON p.id=COALESCE(cl.variation_id,cl.product_id) WHERE cl.session_id=? AND cl.zone_id=? ORDER BY cl.counted_at DESC",[$sid,$zid])->fetchAll(PDO::FETCH_ASSOC);echo json_encode(['ok'=>true,'lines'=>$lines]);exit;}

// S63: save_count_line (single)
if($ajax==='save_count_line'){$d=json_decode(file_get_contents('php://input'),true)??[];$sid=(int)($d['session_id']??0);$zid=(int)($d['zone_id']??0);$pid=(int)($d['product_id']??0);$vid=($d['variation_id']??null)?(int)$d['variation_id']:null;$qty=(int)($d['counted_qty']??0);if(!$sid||!$zid||!$pid){echo json_encode(['ok'=>false,'error'=>'Missing data']);exit;}
$ipid=$vid?:$pid;$exp=(int)(DB::run("SELECT COALESCE(quantity,0) FROM inventory WHERE product_id=? AND store_id=?",[$ipid,$store_id])->fetchColumn()?:0);$disc=$qty-$exp;
$el=DB::run("SELECT id FROM inventory_count_lines WHERE session_id=? AND zone_id=? AND product_id=? AND (variation_id=? OR(variation_id IS NULL AND ? IS NULL))",[$sid,$zid,$pid,$vid,$vid])->fetchColumn();
if($el)DB::run("UPDATE inventory_count_lines SET quantity_counted=?,quantity_expected=? WHERE id=?",[$qty,$exp,$el]);
else DB::run("INSERT INTO inventory_count_lines(session_id,zone_id,product_id,variation_id,quantity_expected,quantity_counted)VALUES(?,?,?,?,?,?)",[$sid,$zid,$pid,$vid,$exp,$qty]);
$ie=DB::run("SELECT id FROM inventory WHERE product_id=? AND store_id=?",[$ipid,$store_id])->fetchColumn();
if($ie)DB::run("UPDATE inventory SET quantity=?,is_counted=1,last_verified_at=NOW() WHERE product_id=? AND store_id=?",[$qty,$ipid,$store_id]);
else DB::run("INSERT INTO inventory(product_id,store_id,tenant_id,quantity,is_counted,last_verified_at)VALUES(?,?,?,?,1,NOW())",[$ipid,$store_id,$tenant_id,$qty]);
DB::run("UPDATE products SET last_counted_at=NOW(),counted_via='zone_walk' WHERE id=? AND tenant_id=?",[$ipid,$tenant_id]);
$tc=(int)DB::run("SELECT COUNT(DISTINCT COALESCE(variation_id,product_id)) FROM inventory_count_lines WHERE session_id=?",[$sid])->fetchColumn();
DB::run("UPDATE inventory_count_sessions SET items_counted=? WHERE id=?",[$tc,$sid]);
echo json_encode(['ok'=>true,'counted_qty'=>$qty,'expected'=>$exp,'discrepancy'=>$disc]);exit;}

// S63: save_count_batch (all variations at once)
if($ajax==='save_count_batch'){$d=json_decode(file_get_contents('php://input'),true)??[];$sid=(int)($d['session_id']??0);$zid=(int)($d['zone_id']??0);$pid=(int)($d['product_id']??0);$items=$d['items']??[];if(!$sid||!$zid||!$pid||!count($items)){echo json_encode(['ok'=>false]);exit;}
$tq=0;foreach($items as $it){$vid=($it['variation_id']??null)?(int)$it['variation_id']:null;$qty=(int)($it['counted_qty']??0);$tq+=$qty;$ipid=$vid?:$pid;$exp=(int)(DB::run("SELECT COALESCE(quantity,0) FROM inventory WHERE product_id=? AND store_id=?",[$ipid,$store_id])->fetchColumn()?:0);$disc=$qty-$exp;
$el=DB::run("SELECT id FROM inventory_count_lines WHERE session_id=? AND zone_id=? AND product_id=? AND(variation_id=? OR(variation_id IS NULL AND ? IS NULL))",[$sid,$zid,$pid,$vid,$vid])->fetchColumn();
if($el)DB::run("UPDATE inventory_count_lines SET quantity_counted=?,quantity_expected=? WHERE id=?",[$qty,$exp,$el]);
else DB::run("INSERT INTO inventory_count_lines(session_id,zone_id,product_id,variation_id,quantity_expected,quantity_counted)VALUES(?,?,?,?,?,?)",[$sid,$zid,$pid,$vid,$exp,$qty]);
$ie=DB::run("SELECT id FROM inventory WHERE product_id=? AND store_id=?",[$ipid,$store_id])->fetchColumn();
if($ie)DB::run("UPDATE inventory SET quantity=?,is_counted=1,last_verified_at=NOW() WHERE product_id=? AND store_id=?",[$qty,$ipid,$store_id]);
else DB::run("INSERT INTO inventory(product_id,store_id,tenant_id,quantity,is_counted,last_verified_at)VALUES(?,?,?,?,1,NOW())",[$ipid,$store_id,$tenant_id,$qty]);
DB::run("UPDATE products SET last_counted_at=NOW(),counted_via='zone_walk' WHERE id=? AND tenant_id=?",[$ipid,$tenant_id]);}
$tc=(int)DB::run("SELECT COUNT(DISTINCT COALESCE(variation_id,product_id)) FROM inventory_count_lines WHERE session_id=?",[$sid])->fetchColumn();
DB::run("UPDATE inventory_count_sessions SET items_counted=? WHERE id=?",[$tc,$sid]);
echo json_encode(['ok'=>true,'total_qty'=>$tq,'items_saved'=>count($items)]);exit;}

// S63: finish_zone
if($ajax==='finish_zone'){$d=json_decode(file_get_contents('php://input'),true)??[];$sid=(int)($d['session_id']??0);$zid=(int)($d['zone_id']??0);if(!$sid||!$zid){echo json_encode(['ok'=>false]);exit;}
$zi=(int)DB::run("SELECT COUNT(DISTINCT COALESCE(variation_id,product_id)) FROM inventory_count_lines WHERE session_id=? AND zone_id=?",[$sid,$zid])->fetchColumn();
DB::run("UPDATE store_zones SET last_walked_at=NOW() WHERE id=? AND store_id=?",[$zid,$store_id]);
$zd=(int)DB::run("SELECT COUNT(DISTINCT cl.zone_id) FROM inventory_count_lines cl WHERE cl.session_id=?",[$sid])->fetchColumn();
DB::run("UPDATE inventory_count_sessions SET zones_completed=? WHERE id=?",[$zd,$sid]);
echo json_encode(['ok'=>true,'zone_items'=>$zi,'zones_completed'=>$zd]);exit;}

if($ajax==='get_zone_line_counts'){$sid=(int)($_GET['session_id']??0);if(!$sid){echo json_encode(['ok'=>false]);exit;}$rows=DB::run("SELECT zone_id,COUNT(DISTINCT COALESCE(variation_id,product_id)) AS cnt,COALESCE(SUM(quantity_counted),0) AS total_qty FROM inventory_count_lines WHERE session_id=? GROUP BY zone_id",[$sid])->fetchAll(PDO::FETCH_ASSOC);$counts=[];$qtys=[];foreach($rows as $r){$counts[(int)$r['zone_id']]=(int)$r['cnt'];$qtys[(int)$r['zone_id']]=(int)$r['total_qty'];}echo json_encode(['ok'=>true,'counts'=>$counts,'qtys'=>$qtys]);exit;}
echo json_encode(['ok'=>false,'error'=>'Unknown']);exit;}

$zones_count=(int)DB::run("SELECT COUNT(*) FROM store_zones WHERE store_id=? AND is_active=1",[$store_id])->fetchColumn();
$active_session=DB::run("SELECT id,status,mode,items_counted,items_total,zones_completed,zones_total FROM inventory_count_sessions WHERE store_id=? AND status IN('in_progress','paused') ORDER BY created_at DESC LIMIT 1",[$store_id])->fetch(PDO::FETCH_ASSOC);
$all_suppliers=DB::run("SELECT id,name FROM suppliers WHERE tenant_id=? AND is_active=1 ORDER BY name",[$tenant_id])->fetchAll(PDO::FETCH_ASSOC);
$all_categories=DB::run("SELECT id,name,parent_id FROM categories WHERE tenant_id=? ORDER BY name",[$tenant_id])->fetchAll(PDO::FETCH_ASSOC);
?>
