-items:center;gap:6px;padding:8px 10px;justify-content:center}.zact{width:32px;height:32px;border:none;border-radius:8px;background:rgba(99,102,241,.15);color:#a5b4fc;cursor:pointer;display:flex;align-items:center;justify-content:center}.zact svg{width:14px;height:14px}.zact.del{background:rgba(239,68,68,.12);color:#f87171}.add-zone-btn{margin:4px 16px 12px;padding:14px;background:rgba(99,102,241,.08);border:2px dashed rgba(99,102,241,.28);border-radius:14px;color:#a5b4fc;font-size:14px;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px}.prog-bar{height:5px;background:rgba(99,102,241,.15);border-radius:3px;overflow:hidden}.prog-fill{height:100%;background:linear-gradient(90deg,#6366f1,#8b5cf6);border-radius:3px;transition:width .5s}.prog-lbl{font-size:11px;color:#94a3b8;margin-top:5px}.rec-ov{display:none;position:fixed;inset:0;z-index:1000;background:rgba(3,7,18,.72);backdrop-filter:blur(8px);align-items:flex-end;justify-content:center;padding-bottom:100px}.rec-ov.active{display:flex}.rec-box{background:rgba(15,23,42,.97);border:1px solid rgba(99,102,241,.4);border-radius:20px;padding:20px;width:calc(100% - 32px)}.rec-ind{display:flex;align-items:center;gap:10px;margin-bottom:14px}.rec-dot{width:12px;height:12px;border-radius:50%;background:#ef4444;animation:recPulse 1s infinite}.rec-dot.done{background:#22c55e;animation:none}@keyframes recPulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(.8)}}.rec-lbl{font-size:13px;font-weight:700}.rec-trans{min-height:46px;font-size:16px;color:#c7d2fe;margin-bottom:14px;line-height:1.4}.rec-send{width:100%;padding:14px;border:none;border-radius:12px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:15px;font-weight:700;cursor:pointer}.rec-cancel{width:100%;margin-top:8px;padding:10px;border:none;border-radius:12px;background:transparent;color:#94a3b8;font-size:13px;cursor:pointer}.modal-ov{display:none;position:fixed;inset:0;z-index:600;background:rgba(0,0,0,.75);backdrop-filter:blur(8px);align-items:flex-end;justify-content:center}.modal-ov.open{display:flex}.modal-box{background:#0c1525;border:1px solid rgba(99,102,241,.3);border-radius:20px 20px 0 0;padding:20px;width:100%;max-height:88dvh;overflow-y:auto}.mhandle{width:36px;height:4px;background:rgba(99,102,241,.3);border-radius:2px;margin:0 auto 16px}.zt-tabs{display:flex;gap:6px;flex-wrap:wrap}.zt-tab{padding:7px 13px;border-radius:20px;font-size:12px;font-weight:600;border:1.5px solid rgba(99,102,241,.2);background:transparent;color:#94a3b8;cursor:pointer}.zt-tab.active{background:rgba(99,102,241,.22);border-color:#6366f1;color:#a5b4fc}.photo-preview{width:100%;height:140px;background:rgba(99,102,241,.07);border:2px dashed rgba(99,102,241,.3);border-radius:12px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;position:relative;overflow:hidden}.photo-preview img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;border-radius:10px}.name-input{flex:1;min-height:44px;padding:10px 14px;background:rgba(99,102,241,.07);border:1.5px solid rgba(99,102,241,.2);border-radius:10px;font-size:15px;color:#e2e8f0;font-family:inherit;outline:none}.name-input:focus{border-color:#6366f1}.voice-mini-btn{padding:10px 14px;border:1.5px solid rgba(239,68,68,.3);border-radius:10px;background:rgba(239,68,68,.1);color:#fca5a5;cursor:pointer;display:flex;align-items:center;gap:6px;font-size:13px;font-weight:700;flex-shrink:0}.voice-mini-btn svg{width:16px;height:16px}.czc{background:rgba(15,23,42,.7);border:1px solid rgba(99,102,241,.2);border-radius:16px;overflow:hidden;margin:0 16px 10px;cursor:pointer;display:flex;align-items:stretch}.czc:active{opacity:.75}.czc-photo{width:78px;flex-shrink:0;background:rgba(99,102,241,.08);display:flex;align-items:center;justify-content:center;min-height:78px;position:relative;overflow:hidden}.czc-photo img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover}.czc-body{f