<script>
const INV={zones:[],session:null,zm:{id:0,name:'',type:'cashier',photo:null,ctx:'hub'},cameraStream:null,zc:{zoneId:null,zoneName:'',lines:[],activeProduct:null}};
const PHP={zonesCount:<?=$zones_count?>,hasSession:<?=$active_session?'true':'false'?>,session:<?=json_encode($active_session?:null)?>};
if(PHP.session)INV.session=PHP.session;
const ZCFG={suppliers:<?=json_encode($all_suppliers,JSON_UNESCAPED_UNICODE)?>,categories:<?=json_encode($all_categories,JSON_UNESCAPED_UNICODE)?>};
let zcFilter={supplier_id:null,category_id:null};
document.addEventListener('DOMContentLoaded',()=>{if(PHP.zonesCount>0){showScreen('screen-hub');loadHub()}else showScreen('screen-welcome')});
function showScreen(id,noPush){document.querySelectorAll('.inv-screen').forEach(s=>s.classList.remove('active'));const el=document.getElementById(id);if(el){el.classList.add('active');window.scrollTo(0,0)}if(!noPush)history.pushState({screen:id},'','#'+id)}
window.addEventListener('popstate',function(e){if(document.getElementById('zoneModal').classList.contains('open')){closeZoneModal();return}if(document.getElementById('cameraOv').classList.contains('open')){closeCamera();return}if(document.getElementById('infoModal').classList.contains('open')){document.getElementById('infoModal').classList.remove('open');return}if(document.getElementById('recOv').classList.contains('active')){recCancel();return}if(e.state&&e.state.screen)showScreen(e.state.screen,true);else location.href='warehouse.php'});
// HUB
async function loadHub(){const d=await api('get_stats');if(!d.ok)return;document.getElementById('stTotal').textContent=d.total;document.getElementById('stCounted').textContent=d.counted;document.getElementById('stZones').textContent=d.zones;INV.session=d.session;if(d.session){const p=d.session.items_total>0?Math.round(d.session.items_counted/d.session.items_total*100):0;document.getElementById('sessBanner').style.display='block';document.getElementById('noSessPanel').style.display='none';document.getElementById('sessLbl').textContent=`${d.session.items_counted} от ${d.session.items_total} артикула (${p}%)`;document.getElementById('sessBar').style.width=p+'%'}else{document.getElementById('sessBanner').style.display='none';document.getElementById('noSessPanel').style.display='block'}await loadZones();renderHubZones()}
async function loadZones(){const d=await api('get_zones');if(d.ok)INV.zones=d.zones}
function renderHubZones(){const w=document.getElementById('hubZones');if(!INV.zones.length){w.innerHTML='<div style="text-align:center;padding:20px;color:#64748b;font-size:13px">Добави поне едно място</div>';return}w.innerHTML=INV.zones.map(z=>zoneCard(z)).join('')}
function renderOnbZones(){document.getElementById('onbZones').innerHTML=INV.zones.map(z=>zoneCard(z)).join('');document.getElementById('zonesBtn').disabled=INV.zones.length===0}
function zoneCard(z){const h=!!z.photo_url;const p=h?`<img src="${esc(z.photo_url)}">`:`<div class="zp-inner"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/><circle cx="12" cy="13" r="4"/></svg><span>Снимка</span></div>`;return`<div class="zone-card"><div class="zone-card-photo${h?'':' no-ph'}" onclick="addPhotoToZone(${z.id})">${p}</div><div class="zone-card-body" onclick="enterZoneFromHub(${z.id})" style="cursor:pointer"><div class="zone-card-name">${esc(z.name)}</div><div style="font-size:11px;color:#94a3b8">${ztLabel(z.zone_type)}</div>${!h?'<div style="font-size:9px;color:rgba(245,158,11,.45);margin-top:4px;font-weight:500">без снимка</div>':''}</div><div class="zone-card-acts"><button class="zact" onclick="editZone(${z.id})"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="zact del" onclick="delZone(${z.id})"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a1 1 0 011-1h4a1 1 0 011 1v2"/></svg></button></div></div>`}
// ONBOARDING
function goConfirm(){renderConfirmZones();showScreen('screen-confirm')}
function renderConfirmZones(){document.getElementById('confirmZones').innerHTML=INV.zones.map(z=>{const p=z.photo_url?`<img src="${esc(z.photo_url)}" style="width:44px;height:44px;object-fit:cover;border-radius:8px;flex-shrink:0">`:`<div style="width:44px;height:44px;background:rgba(99,102,241,.1);border-radius:8px;flex-shrink:0"></div>`;return`<div style="display:flex;align-items:center;gap:10px;padding:8px;background:rgba(15,23,42,.6);border-radius:10px;margin-bottom:6px">${p}<div style="flex:1;font-size:14px;font-weight:600">${esc(z.name)}</div></div>`}).join('')||'<div style="color:#64748b;text-align:center;padding:16px">Няма</div>'}
function renderStartZones(){const s=[...INV.zones].sort((a,b)=>a.zone_type==='storage'?-1:b.zone_type==='storage'?1:0);document.getElementById('startZones').innerHTML=s.map(z=>{const p=z.photo_url?`<img src="${esc(z.photo_url)}" style="width:100%;height:100%;object-fit:cover;position:absolute;inset:0">`:`<div style="display:flex;align-items:center;justify-content:center;height:100%"><svg viewBox="0 0 24 24" fill="none" stroke="#4f46e5" stroke-width="2" style="width:24px;height:24px"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg></div>`;const r=z.zone_type==='storage'?'<span style="font-size:10px;background:rgba(99,102,241,.2);color:#a5b4fc;padding:2px 8px;border-radius:10px;font-weight:700">ПРЕПОРЪЧАНО</span>':'';return`<div style="background:rgba(15,23,42,.7);border:1px solid rgba(99,102,241,.2);border-radius:14px;overflow:hidden;display:flex;align-items:stretch"><div style="width:78px;flex-shrink:0;position:relative;min-height:76px;background:rgba(99,102,241,.08)">${p}</div><div style="flex:1;padding:12px;display:flex;flex-direction:column;gap:4px"><div style="font-size:14px;font-weight:700">${esc(z.name)}</div>${r}</div></div>`}).join('')}
async function doStartCounting(){const r=await api('start_session',{mode:'full'},'POST');if(!r.ok){toast('Грешка','err');return}INV.session={id:r.session_id,mode:r.mode,items_counted:0,items_total:0,zones_completed:0,zones_total:INV.zones.length};showScreen('screen-counting');renderCountingZones()}
function skipToHub(){showScreen('screen-hub');loadHub()}
// COUNTING ZONE PICKER
async function goCountingScreen(){await loadZones();if(!INV.session){const r=await api('start_session',{mode:'full'},'POST');if(r.ok)INV.session={id:r.session_id,mode:r.mode,items_counted:0,items_total:0,zones_completed:0,zones_total:INV.zones.length}}showScreen('screen-counting');renderCountingZones()}
async function renderCountingZones(){const d=INV.session?.zones_completed||0,t=INV.zones.length;if(INV.session){try{const zl=await fetch('inventory.php?ajax=get_zone_line_counts&session_id='+INV.session.id).then(r=>r.json());if(zl.ok){INV._zoneCounts=zl.counts;INV._zoneQtys=zl.qtys||{}}}catch(e){}};document.getElementById('cntLbl').textContent=`${d} от ${t} места преброени`;document.getElementById('cntBar').style.width=t>0?(d/t*100)+'%':'0%';document.getElementById('cntZones').innerHTML=INV.zones.map(z=>{const p=z.photo_url?`<img src="${esc(z.photo_url)}">`:`<div style="display:flex;align-items:center;justify-content:center;height:100%;background:rgba(99,102,241,.08)"><svg viewBox="0 0 24 24" fill="none" stroke="#4f46e5" stroke-width="2" style="width:24px;height:24px"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg></div>`;const cnt=INV._zoneCounts?.[z.id]||0;const done=cnt>0;const zqty=INV._zoneQtys?.[z.id]||0;return`<div class="czc" onclick="enterZone(${z.id})" style="${done?'border-color:rgba(34,197,94,.3)':''}"><div class="czc-photo">${p}</div><div class="czc-body"><div class="czc-name">${esc(z.name)}</div><div style="font-size:11px;color:${done?'#4ade80':'#64748b'};margin-top:2px">${done?cnt+' артикула · '+zqty+' бр.':'Не е започнато'}</div></div><div class="czc-arr">${done?'<svg viewBox="0 0 24 24" fill="none" stroke="#22c55e" stroke-width="2.5" style="width:18px;height:18px"><polyline points="20 6 9 17 4 12"/></svg>':'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><polyline points="9 18 15 12 9 6"/></svg>'}</div></div>`}).join('')}

// ═══ S63: ZONE COUNT ENGINE ═══
async function enterZone(zoneId){const z=INV.zones.find(x=>x.id===zoneId);if(!z)return;INV.zc.zoneId=zoneId;INV.zc.zoneName=z.name;INV.zc.activeProduct=null;INV.zc.lines=[];document.getElementById('zcZoneName').textContent=z.name;document.getElementById('zcSearchInput').value='';document.getElementById('zcResults').style.display='none';document.getElementById('zcActiveCard').innerHTML='';showScreen('screen-zone-count');if(INV.session){const d=await api(`get_zone_lines&zone_id=${zoneId}&session_id=${INV.session.id}`);if(d.ok){INV.zc.lines=d.lines;renderZcCounted()}}}
async function enterZoneFromHub(zoneId){if(!INV.session){const r=await api('start_session',{mode:'full'},'POST');if(!r.ok){toast('Грешка','err');return}INV.session={id:r.session_id,mode:r.mode,items_counted:0,items_total:0,zones_completed:0,zones_total:INV.zones.length}}enterZone(zoneId)}
function exitZoneCount(){INV.zc.activeProduct=null;showScreen('screen-counting');renderCountingZones()}
// SEARCH
let _zcSTO=null;
function onZcSearch(q){q=q.trim();const r=document.getElementById('zcResults');if(q.length<1){clearTimeout(_zcSTO);r.style.display='none';return}clearTimeout(_zcSTO);_zcSTO=setTimeout(async()=>{let searchUrl='products.php?ajax=search&q='+encodeURIComponent(q)+'&store_id=<?=$store_id?>';if(zcFilter.supplier_id)searchUrl+='&supplier_id='+zcFilter.supplier_id;if(zcFilter.category_id)searchUrl+='&category_id='+zcFilter.category_id;const d=await fetch(searchUrl).then(x=>x.json());if(!d||!d.length){r.innerHTML='<div style="padding:16px;text-align:center;font-size:12px;color:#94a3b8">Нищо за "'+esc(q)+'"</div>';r.style.display='block';return}// S65: group by parent_id
const grouped={};d.forEach(p=>{const key=p.parent_id&&p.parent_id!='0'?p.parent_id:p.id;if(!grouped[key]){grouped[key]={...p,_origId:parseInt(key)}}});const gList=Object.values(grouped);
r.innerHTML=gList.slice(0,15).map(p=>{const st=parseInt(p.total_stock||0);const sc=st>0?'#4ade80':'#f87171';const th=p.image_url?'<img src="'+p.image_url+'" style="width:100%;height:100%;object-fit:cover;border-radius:8px">':'<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="rgba(99,102,241,.25)" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="3"/></svg>';return`<div class="zc-result-item" onclick="pickProduct(${p._origId||p.id})"><div style="width:36px;height:36px;border-radius:8px;background:rgba(99,102,241,.08);display:flex;align-items:center;justify-content:center;flex-shrink:0;overflow:hidden">${th}</div><div style="flex:1;min-width:0"><div style="font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(p.name)}</div><div style="font-size:9px;color:#94a3b8">${esc(p.code||'')} · ${esc(p.supplier_name||'')}</div></div><div style="text-align:right;flex-shrink:0"><div style="font-size:12px;font-weight:700;color:#a5b4fc">${fmtPrice(p.retail_price)}</div><div style="font-size:9px;color:${sc}">${st} бр.</div></div></div>`}).join('');r.style.display='block'},250)}
// S65: Bulgarian word-to-number
function bgWordToNum(t){const w=t.trim().toLowerCase();const ones={'нула':0,'един':1,'една':1,'едно':1,'два':2,'две':2,'три':3,'четири':4,'пет':5,'шест':6,'седем':7,'осем':8,'девет':9,'десет':10,'единадесет':11,'единайсет':11,'дванадесет':12,'дванайсет':12,'тринадесет':13,'тринайсет':13,'четиринадесет':14,'четиринайсет':14,'петнадесет':15,'петнайсет':15,'шестнадесет':16,'шестнайсет':16,'седемнадесет':17,'седемнайсет':17,'осемнадесет':18,'осемнайсет':18,'деветнадесет':19,'деветнайсет':19,'двадесет':20,'двайсет':20,'тридесет':30,'трийсет':30,'четиридесет':40,'четирийсет':40,'петдесет':50,'шестдесет':60,'седемдесет':70,'осемдесет':80,'деветдесет':90,'сто':100};const n=parseInt(w);if(!isNaN(n))return n;if(ones[w]!==undefined)return ones[w];const m=w.match(/^(.+?)\s+и\s+(.+)$/);if(m){const a=ones[m[1].trim()];const b=ones[m[2].trim()];if(a!==undefined&&b!==undefined)return a+b}return null}
function zcVoiceSearch(){startVoice(t=>{document.getElementById('zcSearchInput').value=t;onZcSearch(t)},'Кажи какво търсиш...')}
// S66: CAMERA BARCODE SCANNER
let _bcStream=null,_bcDetector=null,_bcAnimFrame=null;
async function zcOpenBarcodeCamera(){
if(!('BarcodeDetector' in window)){toast('Баркод скенерът не се поддържа от браузъра','warn');return}
try{_bcStream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment',width:{ideal:1280}}});
const v=document.getElementById('bcVideo');v.srcObject=_bcStream;document.getElementById('bcCamOv').style.display='flex';
_bcDetector=new BarcodeDetector({formats:['ean_13','ean_8','code_128','code_39','upc_a','upc_e','qr_code']});
_bcScanLoop()}catch(e){toast('Камерата не е достъпна','err')}}
async function _bcScanLoop(){if(!_bcStream)return;const v=document.getElementById('bcVideo');if(v.readyState<2){_bcAnimFrame=requestAnimationFrame(_bcScanLoop);return}
try{const codes=await _bcDetector.detect(v);if(codes.length>0){const code=codes[0].rawValue;zcCloseBarcodeCamera();toast('Сканирано: '+code,'ok');zcBarcodeScan(code);return}}catch(e){}
_bcAnimFrame=requestAnimationFrame(_bcScanLoop)}
function zcCloseBarcodeCamera(){document.getElementById('bcCamOv').style.display='none';if(_bcAnimFrame)cancelAnimationFrame(_bcAnimFrame);_bcAnimFrame=null;if(_bcStream){_bcStream.getTracks().forEach(t=>t.stop());_bcStream=null}_bcDetector=null}
// S66: BARCODE SCANNER (physical USB/BT scanner sends keystrokes + Enter)
let _bcBuf='',_bcTimer=null;
document.addEventListener('keydown',function(e){
if(!document.getElementById('screen-zone-count')?.classList.contains('active'))return;
if(document.activeElement&&(document.activeElement.tagName==='INPUT'||document.activeElement.contentEditable==='true'))return;
if(e.key==='Enter'&&_bcBuf.length>=3){e.preventDefault();const code=_bcBuf.trim();_bcBuf='';clearTimeout(_bcTimer);zcBarcodeScan(code);return}
if(e.key.length===1){_bcBuf+=e.key;clearTimeout(_bcTimer);_bcTimer=setTimeout(()=>{_bcBuf=''},150)}});
async function zcBarcodeScan(code){toast('Сканирам: '+code+'...');let searchUrl='products.php?ajax=search&q='+encodeURIComponent(code)+'&store_id=<?=$store_id?>';if(zcFilter.supplier_id)searchUrl+='&supplier_id='+zcFilter.supplier_id;if(zcFilter.category_id)searchUrl+='&category_id='+zcFilter.category_id;const d=await fetch(searchUrl).then(r=>r.json());if(!d||!d.length){toast('Баркод '+code+' не е намерен','warn');document.getElementById('zcSearchInput').value=code;return}
const grouped={};d.forEach(p=>{const key=p.parent_id&&p.parent_id!='0'?p.parent_id:p.id;if(!grouped[key])grouped[key]={...p,_origId:parseInt(key)}});const gList=Object.values(grouped);
if(gList.length===1){toast(esc(gList[0].name),'ok');pickProduct(gList[0]._origId||gList[0].id)}else{document.getElementById('zcSearchInput').value=code;onZcSearch(code)}}
// S66: FILTER LOGIC
function zcToggleFilter(type){const dd=document.getElementById('zcFilterDD');const isOpen=dd.style.display==='block'&&dd.dataset.type===type;if(isOpen){dd.style.display='none';return}dd.dataset.type=type;const items=type==='supplier'?ZCFG.suppliers:ZCFG.categories.filter(c=>!c.parent_id);const curId=type==='supplier'?zcFilter.supplier_id:zcFilter.category_id;dd.innerHTML='<div class="zc-filter-dd-item'+(curId===null?' sel':'')+'" onclick="zcSetFilter(\''+type+'\',null)">Всички</div>'+items.map(it=>'<div class="zc-filter-dd-item'+(curId==it.id?' sel':'')+'" onclick="zcSetFilter(\''+type+'\','+it.id+')">'+esc(it.name)+'</div>').join('');dd.style.display='block'}
function zcSetFilter(type,id){if(type==='supplier'){zcFilter.supplier_id=id;const btn=document.getElementById('zcFiltSup');if(id){const s=ZCFG.suppliers.find(x=>x.id==id);btn.textContent=s?s.name:'Доставчик';btn.classList.add('active')}else{btn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12"><path d="M16 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="8.5" cy="7" r="4"/></svg> Доставчик';btn.classList.remove('active')}}else{zcFilter.category_id=id;const btn=document.getElementById('zcFiltCat');if(id){const c=ZCFG.categories.find(x=>x.id==id);btn.textContent=c?c.name:'Категория';btn.classList.add('active')}else{btn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12"><path d="M22 19a2 2 0 01-2 2H4a2 2 0 01-2-2V5a2 2 0 012-2h5l2 3h9a2 2 0 012 2z"/></svg> Категория';btn.classList.remove('active')}}document.getElementById('zcFilterDD').style.display='none';document.getElementById('zcFiltClear').style.display=(zcFilter.supplier_id||zcFilter.category_id)?'flex':'none';const q=document.getElementById('zcSearchInput').value.trim();if(q)onZcSearch(q)}
function zcClearFilters(){zcFilter.supplier_id=null;zcFilter.category_id=null;document.getElementById('zcFiltClear').style.display='none';document.getElementById('zcFiltSup').innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12"><path d="M16 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="8.5" cy="7" r="4"/></svg> Доставчик';document.getElementById('zcFiltSup').classList.remove('active');document.getElementById('zcFiltCat').innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12"><path d="M22 19a2 2 0 01-2 2H4a2 2 0 01-2-2V5a2 2 0 012-2h5l2 3h9a2 2 0 012 2z"/></svg> Категория';document.getElementById('zcFiltCat').classList.remove('active');document.getElementById('zcFilterDD').style.display='none';const q=document.getElementById('zcSearchInput').value.trim();if(q)onZcSearch(q)}
// PICK PRODUCT
async function pickProduct(pid){document.getElementById('zcResults').style.display='none';document.getElementById('zcSearchInput').value='';
// S66: Check if already counted in this zone
const existingLine=INV.zc.lines.find(l=>l.product_id==pid);
if(existingLine&&!INV.zc._dupConfirmed){
const tq=existingLine.totalQty!==undefined?existingLine.totalQty:(parseInt(existingLine.counted_qty)||0);
const ok=confirm('⚠️ '+esc(existingLine.name||'Този артикул')+' вече е преброен тук ('+tq+' бр.)\n\nИскаш ли да промениш бройката?');
if(!ok){document.getElementById('zcSearchInput').focus();return}
INV.zc._dupConfirmed=true;}
const d=await fetch('products.php?ajax=product_detail&id='+pid).then(r=>r.json());if(!d||d.error){toast('Грешка','err');return}const p=d.product;const vars=d.variations||[];INV.zc.activeProduct={id:p.id,name:p.name,code:p.code,variations:vars};let h='<div class="zc-active-card">';h+=`<div style="font-size:15px;font-weight:700;margin-bottom:2px">${esc(p.name)}</div>`;h+=`<div style="font-size:12px;color:#94a3b8;margin-bottom:12px">${esc(p.code||'')} \u00b7 ${fmtPrice(p.retail_price)}</div>`;

if(vars.length>0){vars.forEach((v,i)=>{const lb=[v.size,v.color].filter(Boolean).join(' · ')||esc(v.name);const st=parseInt(v.total_stock||0);h+=`<div class="zc-var-row" id="zcVar${i}"><div><div class="zc-var-label">${esc(lb)}</div><div style="font-size:10px;color:#64748b">Сега: ${st}</div></div><div class="zc-stepper"><button class="zc-stepper-btn minus" onclick="zcAdj(${i},-1)">−</button><span class="zc-stepper-val" id="zcVal${i}">${st}</span><button class="zc-stepper-btn plus" onclick="zcAdj(${i},1)">+</button></div></div>`});h+=`<div style="display:flex;align-items:center;justify-content:space-between;margin-top:12px"><div style="font-size:13px;color:#94a3b8">Общо: <span style="font-size:18px;font-weight:800;color:#c7d2fe" id="zcTotal">0</span></div><div style="display:flex;gap:8px"><button onclick="zcCancelProduct()" style="padding:10px 18px;background:transparent;border:1.5px solid rgba(99,102,241,.25);border-radius:10px;font-size:13px;font-weight:600;color:#94a3b8;cursor:pointer">Откажи</button><button onclick="zcSaveBatch()" style="padding:10px 24px;background:linear-gradient(135deg,#6366f1,#8b5cf6);border:none;border-radius:10px;font-size:14px;font-weight:700;color:#fff;cursor:pointer">Запази</button></div></div>`}
else{const st=d.stocks?.reduce((a,s)=>a+parseInt(s.qty||0),0)||0;h+=`<div class="zc-var-row"><div><div class="zc-var-label">Бройка</div><div style="font-size:10px;color:#64748b">Сега: ${st}</div></div><div class="zc-stepper"><button class="zc-stepper-btn minus" onclick="zcAdj(0,-1)">−</button><span class="zc-stepper-val" id="zcVal0">${st}</span><button class="zc-stepper-btn plus" onclick="zcAdj(0,1)">+</button></div></div><div style="margin-top:12px;display:flex;justify-content:flex-end;gap:8px"><button onclick="zcCancelProduct()" style="padding:10px 18px;background:transparent;border:1.5px solid rgba(99,102,241,.25);border-radius:10px;font-size:13px;font-weight:600;color:#94a3b8;cursor:pointer">Откажи</button><button onclick="zcSaveSingle()" style="padding:10px 24px;background:linear-gradient(135deg,#6366f1,#8b5cf6);border:none;border-radius:10px;font-size:14px;font-weight:700;color:#fff;cursor:pointer">Запази</button></div>`}
h+='</div>';document.getElementById('zcActiveCard').innerHTML=h;updateZcTotal()}
// S65: Manual / Voice mode handlers
function zcStartManual(){INV.zc._forceMode='manual';const ap=INV.zc.activeProduct;if(ap)pickProduct(ap.id)}
function zcStartVoiceCount(){const ap=INV.zc.activeProduct;if(!ap)return;INV.zc._forceMode='voice';pickProduct(ap.id);setTimeout(()=>{const card=document.getElementById('zcActiveCard');if(!card){console.log('no card');return}const ac=card.querySelector('.zc-active-card');if(!ac){console.log('no ac, card html:',card.innerHTML.substring(0,100));return}const el=document.createElement('div');el.id='zcVoiceZone';el.style.cssText='position:sticky;top:0;z-index:55;background:#0c1525;padding-bottom:8px';el.innerHTML='<div style="border:1px solid rgba(239,68,68,.25);border-radius:14px;padding:14px;background:rgba(239,68,68,.06)"><div style="font-size:14px;font-weight:700;color:#c7d2fe;margin-bottom:10px">\ud83c\udf99 \u0413\u043b\u0430\u0441\u043e\u0432\u043e \u0431\u0440\u043e\u0435\u043d\u0435</div><div style="font-size:13px;color:#94a3b8;margin-bottom:12px">\u0418\u043c\u0430 \u043b\u0438 \u0440\u0430\u0437\u043b\u0438\u043a\u0438 \u0441 \u0431\u0440\u043e\u0439\u043a\u0438\u0442\u0435 \u0432 \u0441\u0438\u0441\u0442\u0435\u043c\u0430\u0442\u0430?</div><div style="display:flex;gap:10px"><button onclick="zcVoiceNoDiff()" style="flex:1;padding:12px;border:1.5px solid rgba(34,197,94,.3);border-radius:12px;background:transparent;color:#4ade80;font-size:14px;font-weight:600;cursor:pointer">\u041d\u0435</button><button onclick="zcVoiceYesDiff()" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#ef4444,#dc2626);color:#fff;font-size:14px;font-weight:700;cursor:pointer">\u0414\u0430</button></div></div>';const ac2=card.querySelector('.zc-active-card');if(ac2){const nameDiv=ac2.querySelector('div');if(nameDiv&&nameDiv.nextSibling){ac2.insertBefore(el,nameDiv.nextSibling.nextSibling)}else{ac2.prepend(el)}}else{card.prepend(el)}},200)}
function zcVoiceNoDiff(){const ap=INV.zc.activeProduct;if(!ap)return;if(ap.variations.length>0){zcSaveBatch()}else{zcSaveSingle()}}
function zcVoiceYesDiff(){const vz=document.getElementById('zcVoiceZone');if(!vz){toast('Грешка: няма voice зона','err');return}vz.innerHTML='<div style="border:1px solid rgba(239,68,68,.25);border-radius:14px;padding:14px;background:rgba(239,68,68,.06)"><div style="font-size:13px;color:#94a3b8;margin-bottom:10px">\u0414\u0438\u043a\u0442\u0443\u0432\u0430\u0439 \u0440\u0430\u0437\u043b\u0438\u043a\u0438\u0442\u0435. \u041c\u043e\u0436\u0435 \u0434\u0430 \u0441\u043f\u0438\u0440\u0430\u0448 \u0438 \u043f\u0440\u043e\u0434\u044a\u043b\u0436\u0430\u0432\u0430\u0448.</div><div id="zcTransBox" contenteditable="false" style="min-height:60px;max-height:150px;overflow-y:auto;background:rgba(15,23,42,.8);border:1px solid rgba(99,102,241,.2);border-radius:12px;padding:12px;font-size:14px;color:#e2e8f0;line-height:1.6;margin-bottom:10px"></div><div id="zcVoiceBtns" style="display:flex;gap:8px"><button onclick="zcStartDictation()" id="zcDictBtn" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#ef4444,#dc2626);color:#fff;font-size:14px;font-weight:700;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:6px"><span style="width:10px;height:10px;border-radius:50%;background:#fff;animation:recPulse 1s infinite"></span>\u0417\u0430\u043f\u0438\u0441\u0432\u0430\u0439</button><button onclick="zcFinishDictation()" id="zcDoneBtn" style="display:none;flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;font-size:14px;font-weight:700;cursor:pointer">\u0413\u043e\u0442\u043e\u0432\u043e</button></div></div>'}
// STEPPER
function zcAdj(i,d){const el=document.getElementById('zcVal'+i);if(!el)return;let v=parseInt(el.textContent)||0;v=Math.max(0,v+d);el.textContent=v;updateZcTotal()}
function updateZcTotal(){const t=document.getElementById('zcTotal');if(!t)return;let s=0;const ap=INV.zc.activeProduct;if(!ap)return;const n=ap.variations.length||1;for(let i=0;i<n;i++){const e=document.getElementById('zcVal'+i);if(e)s+=parseInt(e.textContent)||0}t.textContent=s}
// S65: Dictation engine
let _zcRec=null,_zcRecTimeout=null;
function zcStartDictation(){if(_zcRec){try{_zcRec.abort()}catch(e){}_zcRec=null}const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){toast('Гласът не се поддържа');return}_zcRec=new SR();_zcRec.lang='bg-BG';_zcRec.continuous=true;_zcRec.interimResults=true;const box=document.getElementById('zcTransBox');box.contentEditable='false';document.getElementById('zcDictBtn').style.display='none';document.getElementById('zcDoneBtn').style.display='block';_zcRec.onresult=e=>{let fin='',interim='';for(let i=0;i<e.results.length;i++){if(e.results[i].isFinal)fin+=e.results[i][0].transcript+' ';else interim+=e.results[i][0].transcript}const prev=box.dataset.confirmed||'';box.innerHTML=esc(prev+fin)+(interim?'<span style="color:#64748b">'+esc(interim)+'</span>':'');box.scrollTop=box.scrollHeight;clearTimeout(_zcRecTimeout);_zcRecTimeout=setTimeout(()=>{zcStopDictation();toast('Записът спря (5 мин)','warn')},300000)};_zcRec.onend=()=>{const box2=document.getElementById('zcTransBox');if(box2){box2.dataset.confirmed=(box2.dataset.confirmed||'')+box2.textContent.substring((box2.dataset.confirmed||'').length);box2.contentEditable='true'}document.getElementById('zcDictBtn').innerHTML='\u25b6 Продължи запис';document.getElementById('zcDictBtn').style.display='block'};_zcRec.onerror=()=>{toast('Грешка с микрофона','err');zcStopDictation()};_zcRec.start();clearTimeout(_zcRecTimeout);_zcRecTimeout=setTimeout(()=>{zcStopDictation();toast('Записът спря (5 мин)','warn')},300000)}
function zcStopDictation(){if(_zcRec)try{_zcRec.stop()}catch(e){};clearTimeout(_zcRecTimeout)}
function zcFinishDictation(){zcStopDictation();const box=document.getElementById('zcTransBox');if(!box)return;const txt=box.textContent.trim();if(!txt){toast('Не чух нищо','warn');return}INV.zc._lastTranscript=txt;zcParseAndApply(txt)}
function zcParseAndApply(txt){const ap=INV.zc.activeProduct;if(!ap)return;const vars=ap.variations;const parts=txt.split(/[,\.;]+/);let applied=0;parts.forEach(part=>{part=part.trim().toLowerCase();if(!part)return;let bestIdx=-1,bestScore=0;vars.forEach((v,i)=>{let score=0;const sz=(v.size||'').toLowerCase();const cl=(v.color||'').toLowerCase();if(sz&&part.includes(sz))score+=2;if(cl&&part.includes(cl))score+=2;if(score>bestScore){bestScore=score;bestIdx=i}});if(bestIdx>=0){const words=part.split(/\s+/);let num=null;for(let w of words){const n=bgWordToNum(w);if(n!==null){num=n;break}}if(num!==null){const el=document.getElementById('zcVal'+bestIdx);if(el){el.textContent=num;applied++}}}});updateZcTotal();const vz=document.getElementById('zcVoiceZone');if(vz){vz.innerHTML='<div style="border:1px solid rgba(239,68,68,.25);border-radius:14px;padding:14px;background:rgba(239,68,68,.06)"><div style="font-size:13px;color:#94a3b8;margin-bottom:6px">Попълнени: '+applied+' вариации</div><div id="zcTransBox" contenteditable="true" style="min-height:40px;max-height:120px;overflow-y:auto;background:rgba(15,23,42,.8);border:1px solid rgba(99,102,241,.2);border-radius:12px;padding:10px;font-size:13px;color:#e2e8f0;line-height:1.5;margin-bottom:10px">'+esc(txt)+'</div><div style="display:flex;gap:8px"><button onclick="zcVoiceConfirmSave()" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;font-size:14px;font-weight:700;cursor:pointer">Да, запази</button><button onclick="zcReapplyText()" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:14px;font-weight:700;cursor:pointer">Приложи пак</button><button onclick="zcStartDictation()" style="padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#ef4444,#dc2626);color:#fff;font-size:14px;font-weight:700;cursor:pointer">+Глас</button></div></div>'}}
function zcVoiceConfirmSave(){const ap=INV.zc.activeProduct;if(!ap)return;if(ap.variations.length>0)zcSaveBatch();else zcSaveSingle()}
function zcVoiceEdit(){const vz=document.getElementById('zcVoiceZone');if(!vz)return;vz.innerHTML='<div style="border:1px solid rgba(239,68,68,.25);border-radius:14px;padding:14px;background:rgba(239,68,68,.06)"><div style="font-size:13px;color:#94a3b8;margin-bottom:10px">Редактирай текста и натисни "Приложи":</div><div id="zcTransBox" contenteditable="true" style="min-height:60px;max-height:150px;overflow-y:auto;background:rgba(15,23,42,.8);border:1px solid rgba(99,102,241,.2);border-radius:12px;padding:12px;font-size:14px;color:#e2e8f0;line-height:1.6;margin-bottom:10px">'+esc(INV.zc._lastTranscript||'')+'</div><div style="display:flex;gap:8px"><button onclick="zcReapplyText()" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:14px;font-weight:700;cursor:pointer">Приложи</button><button onclick="zcStartDictation()" style="flex:1;padding:12px;border:none;border-radius:12px;background:linear-gradient(135deg,#ef4444,#dc2626);color:#fff;font-size:14px;font-weight:700;cursor:pointer">Диктувай пак</button></div></div>'}
function zcReapplyText(){const box=document.getElementById('zcTransBox');if(!box)return;zcParseAndApply(box.textContent.trim())}
// V11: EDIT COUNTED
function zcEditCounted(pid){if(!pid)return;INV.zc._dupConfirmed=true;pickProduct(pid)}
// V9: CANCEL
function zcCancelProduct(){document.getElementById('zcActiveCard').innerHTML='';INV.zc.activeProduct=null;INV.zc._dupConfirmed=false;document.getElementById('zcSearchInput').value='';document.getElementById('zcSearchInput').focus()}
// SAVE
async function zcSaveSingle(){const ap=INV.zc.activeProduct;if(!ap||!INV.session)return;const q=parseInt(document.getElementById('zcVal0')?.textContent)||0;
const exp0=parseInt(document.querySelector('#zcActiveCard .zc-var-row div[style*="font-size:10px"]')?.textContent?.match(/\d+/)?.[0])||0;
if(q!==exp0&&!INV.zc._discConfirmed){const diff=q-exp0;const sign=diff>0?'+':'';if(!confirm('⚠️ Разлика: '+sign+diff+' бр.\nБеше: '+exp0+' → Сега: '+q+'\n\nСигурен ли си?')){return}INV.zc._discConfirmed=true}
const r=await api('save_count_line',{session_id:INV.session.id,zone_id:INV.zc.zoneId,product_id:ap.id,variation_id:null,counted_qty:q},'POST');if(r.ok){toast('Записано','ok');INV.zc._dupConfirmed=false;INV.zc._discConfirmed=false;INV.zc.lines=INV.zc.lines.filter(l=>l.product_id!=ap.id);INV.zc.lines.unshift({product_id:ap.id,name:ap.name,code:ap.code,totalQty:q,variations:[]});renderZcCounted();showElsewhere(ap.id,ap.name,[])}else toast('Грешка','err')}
async function zcSaveBatch(){const ap=INV.zc.activeProduct;if(!ap||!INV.session)return;const items=[];let totalNew=0,totalOld=0;ap.variations.forEach((v,i)=>{const q=parseInt(document.getElementById('zcVal'+i)?.textContent)||0;items.push({variation_id:v.id,counted_qty:q});totalNew+=q;totalOld+=parseInt(v.total_stock||0)});
if(totalNew!==totalOld&&!INV.zc._discConfirmed){const diff=totalNew-totalOld;const sign=diff>0?'+':'';if(!confirm('⚠️ Разлика: '+sign+diff+' бр. общо\nБеше: '+totalOld+' → Сега: '+totalNew+'\n\nСигурен ли си?')){return}INV.zc._discConfirmed=true}
const r=await api('save_count_batch',{session_id:INV.session.id,zone_id:INV.zc.zoneId,product_id:ap.id,items},'POST');if(r.ok){toast(`Записано: ${r.total_qty} бр.`,'ok');INV.zc._dupConfirmed=false;INV.zc._discConfirmed=false;INV.zc.lines=INV.zc.lines.filter(l=>l.product_id!=ap.id);INV.zc.lines.unshift({product_id:ap.id,name:ap.name,code:ap.code,totalQty:r.total_qty,variations:ap.variations,items});renderZcCounted();showElsewhere(ap.id,ap.name,ap.variations)}else toast('Грешка','err')}
// ═══ S64: ELSEWHERE ("Имаш ли другаде?") ═══
let EW={productId:null,productName:'',variations:[],savedItems:[],selectedZone:null,phase:'ask'};
function showElsewhere(pid,pname,vars){EW={productId:pid,productName:pname,variations:vars||[],savedItems:[],selectedZone:null,phase:'ask'};document.getElementById('ewSub').textContent=esc(pname);document.getElementById('ewZones').innerHTML='';document.getElementById('ewStepper').style.display='none';document.getElementById('ewStepper').innerHTML='';document.getElementById('ewChips').style.display='flex';document.getElementById('ewSaveRow').style.display='none';document.getElementById('ewTitle').textContent='Имаш ли от този артикул другаде?';document.getElementById('ewPanel').classList.add('open')}
function ewNo(){document.getElementById('ewPanel').classList.remove('open');ewFinish()}
function ewYes(){EW.phase='pick';document.getElementById('ewChips').style.display='none';document.getElementById('ewTitle').textContent='Къде другаде имаш?';const cur=INV.zc.zoneId;const zones=INV.zones.filter(z=>z.id!=cur);document.getElementById('ewZones').innerHTML=zones.map(z=>{const ph=z.photo_url?'<img src="'+esc(z.photo_url)+'">':'<svg viewBox="0 0 24 24" fill="none" stroke="#4f46e5" stroke-width="1.5" width="20" height="20"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg>';return'<div class="ew-zone-item" onclick="ewPickZone('+z.id+',this)"><div class="ew-zone-photo">'+ph+'</div><div style="flex:1"><div style="font-size:14px;font-weight:700">'+esc(z.name)+'</div><div style="font-size:11px;color:#94a3b8">'+ztLabel(z.zone_type)+'</div></div><svg viewBox="0 0 24 24" fill="none" stroke="#6366f1" stroke-width="2" width="18" height="18"><polyline points="9 18 15 12 9 6"/></svg></div>'}).join('')||'<div style="color:#64748b;text-align:center;padding:16px">Няма други места</div>'}
function ewPickZone(zid,el){EW.selectedZone=zid;document.querySelectorAll('.ew-zone-item').forEach(e=>e.style.borderColor='rgba(99,102,241,.15)');el.style.borderColor='#6366f1';const st=document.getElementById('ewStepper');st.style.display='block';st.innerHTML='';document.getElementById('ewSaveRow').style.display='block';if(EW.variations.length>0){let h='';EW.variations.forEach((v,i)=>{const lb=[v.size,v.color].filter(Boolean).join(' · ')||esc(v.name||'');h+='<div class="zc-var-row"><div><div class="zc-var-label">'+esc(lb)+'</div></div><div class="zc-stepper"><button class="zc-stepper-btn minus" onclick="ewAdj('+i+',-1)">−</button><span class="zc-stepper-val" id="ewVal'+i+'">0</span><button class="zc-stepper-btn plus" onclick="ewAdj('+i+',1)">+</button></div></div>'});st.innerHTML=h}else{st.innerHTML='<div class="zc-var-row"><div><div class="zc-var-label">Бройка</div></div><div class="zc-stepper"><button class="zc-stepper-btn minus" onclick="ewAdj(0,-1)">−</button><span class="zc-stepper-val" id="ewVal0">0</span><button class="zc-stepper-btn plus" onclick="ewAdj(0,1)">+</button></div></div>'}}
function ewAdj(i,d){const el=document.getElementById('ewVal'+i);if(!el)return;let v=parseInt(el.textContent)||0;v=Math.max(0,v+d);el.textContent=v}
async function ewSaveAndNext(){if(!EW.selectedZone||!INV.session){toast('Няма избрана зона','err');return}try{const zid=EW.selectedZone;let r;if(EW.variations.length>0){const items=[];EW.variations.forEach((v,i)=>{items.push({variation_id:v.id,counted_qty:parseInt(document.getElementById('ewVal'+i)?.textContent)||0})});r=await api('save_count_batch',{session_id:INV.session.id,zone_id:zid,product_id:EW.productId,items},'POST')}else{const q=parseInt(document.getElementById('ewVal0')?.textContent)||0;r=await api('save_count_line',{session_id:INV.session.id,zone_id:zid,product_id:EW.productId,variation_id:null,counted_qty:q},'POST')}if(!r||!r.ok){toast('Грешка: '+(r?.error||'неизвестна'),'err');return}const zname=INV.zones.find(z=>z.id===zid)?.name||'';toast('Записано за '+zname,'ok');EW.savedItems.push(zid);document.getElementById('ewStepper').style.display='none';document.getElementById('ewStepper').innerHTML='';document.getElementById('ewSaveRow').style.display='none';EW.selectedZone=null;document.getElementById('ewTitle').textContent='Още някъде?';document.getElementById('ewChips').style.display='flex';document.getElementById('ewChips').innerHTML='<button onclick="ewNo()" style="flex:1;padding:13px;border:1.5px solid rgba(99,102,241,.25);border-radius:12px;background:transparent;color:#e2e8f0;font-size:14px;font-weight:600;cursor:pointer">Не, готово</button><button onclick="ewYes()" style="flex:1;padding:13px;border:none;border-radius:12px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:14px;font-weight:700;cursor:pointer">Да, още</button>';const doneZones=EW.savedItems;document.querySelectorAll('.ew-zone-item').forEach(el=>{const zid2=parseInt(el.getAttribute('onclick')?.match(/\d+/)?.[0]);if(doneZones.includes(zid2))el.style.opacity='.4'})}catch(e){toast('Грешка: '+e.message,'err')}}
function ewFinish(){document.getElementById('zcActiveCard').innerHTML='';INV.zc.activeProduct=null;document.getElementById('zcSearchInput').value='';document.getElementById('zcSearchInput').focus()}
// COUNTED LIST
function renderZcCounted(){const list=document.getElementById('zcCountedList');const hdr=document.getElementById('zcCountedHdr');const badge=document.getElementById('zcCountBadge');const sub=document.getElementById('zcZoneSub');if(!INV.zc.lines.length){list.innerHTML='';hdr.style.display='none';badge.textContent='0';sub.textContent='0 преброени';return}hdr.style.display='';const pm={};INV.zc.lines.forEach(l=>{let gkey,gname,gcode;if(l.totalQty!==undefined){gname=(l.name||'').split(' / ')[0].trim();gcode=(l.code||'').split('-').slice(0,2).join('-');gkey=l.product_id+'_parent';if(!pm[gkey])pm[gkey]={name:gname,code:gcode,totalQty:0,varDetails:[]};pm[gkey].totalQty=l.totalQty;if(l.items&&l.variations){l.items.forEach((it,i)=>{const v=l.variations[i];if(v)pm[gkey].varDetails.push({label:[v.size,v.color].filter(Boolean).join(' / '),qty:it.counted_qty||0})})}}else{const pid=l.parent_id||l.product_id;gname=(l.name||'').split(' / ')[0].trim();gcode=(l.code||'').split('-').slice(0,2).join('-');gkey=pid+'_parent';if(!pm[gkey])pm[gkey]={name:gname,code:gcode,totalQty:0,varDetails:[]};const qty=parseInt(l.counted_qty)||0;pm[gkey].totalQty+=qty;const sz=l.size||'';const cl=l.color||'';if(sz||cl){const lb=[sz,cl].filter(Boolean).join(' / ');const ex=pm[gkey].varDetails.find(v=>v.label===lb);if(ex)ex.qty=qty;else pm[gkey].varDetails.push({label:lb,qty:qty})}}});const grouped=Object.values(pm);badge.textContent=grouped.length;sub.textContent=grouped.length+' преброени';list.innerHTML=grouped.map((p,gi)=>{const hv=p.varDetails.length>1;const vh=hv?'<div id="zcExp'+gi+'" style="display:none;margin-top:8px;padding-top:8px;border-top:1px solid rgba(99,102,241,.1)">'+p.varDetails.map(v=>'<div style="display:flex;justify-content:space-between;padding:3px 0;font-size:12px"><span style="color:#94a3b8">'+esc(v.label)+'</span><span style="color:#c7d2fe;font-weight:700">'+v.qty+'</span></div>').join('')+'</div>':'';const ar=hv?'<svg viewBox="0 0 24 24" fill="none" stroke="#6366f1" stroke-width="2" width="14" height="14" style="margin-left:4px" id="zcArr'+gi+'"><polyline points="6 9 12 15 18 9"/></svg>':'';const ck=hv?' onclick="toggleZcExp('+gi+')"':'';const pid=Object.keys(pm).find(k=>pm[k]===p);const realPid=pid?parseInt(pid.replace('_parent','')):0;
return'<div class="zc-counted-item"'+ck+'><div style="display:flex;justify-content:space-between;align-items:center"><div><div style="font-size:14px;font-weight:700">'+esc(p.name)+ar+'</div><div style="font-size:11px;color:#94a3b8;margin-top:2px">'+esc(p.code)+(p.varDetails.length>1?' \u00b7 '+p.varDetails.length+' вариации':'')+'</div></div><div style="display:flex;align-items:center;gap:8px"><button onclick="event.stopPropagation();zcEditCounted('+realPid+')" style="width:28px;height:28px;border-radius:7px;border:1px solid rgba(99,102,241,.25);background:rgba(99,102,241,.1);color:#a5b4fc;cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><svg viewBox="0 0 24 24" fill="none" stroke="#22c55e" stroke-width="2.5" width="16" height="16"><polyline points="20 6 9 17 4 12"/></svg><span style="font-size:18px;font-weight:800;color:#4ade80">'+p.totalQty+'</span></div></div>'+vh+'</div>'}).join('')}

function toggleZcExp(i){const el=document.getElementById('zcExp'+i);const ar=document.getElementById('zcArr'+i);if(!el)return;if(el.style.display==='none'){el.style.display='block';if(ar)ar.style.transform='rotate(180deg)'}else{el.style.display='none';if(ar)ar.style.transform='rotate(0)'}}

// FINISH ZONE
async function finishZone(){if(!INV.session||!INV.zc.zoneId)return;if(!INV.zc.lines.length){toast('Не си преброил нищо тук','warn');return}const r=await api('finish_zone',{session_id:INV.session.id,zone_id:INV.zc.zoneId},'POST');if(r.ok){toast(`Място завършено! ${r.zone_items} артикула`,'ok');INV.session.zones_completed=r.zones_completed;setTimeout(()=>{showScreen('screen-counting');renderCountingZones()},1200)}else toast('Грешка','err')}
// ZONE MODAL
function openZoneModal(ctx){INV.zm={id:0,name:'',type:'cashier',photo:null,ctx:ctx||'hub'};document.getElementById('zmTitle').textContent='Добави място';document.getElementById('zmNameInput').value='';document.getElementById('zmPhotoImg').style.display='none';document.getElementById('zmPhotoImg').src='';document.getElementById('zmPhotoLabel').textContent='Добави снимка';document.querySelectorAll('.zt-tab').forEach(t=>t.classList.toggle('active',t.dataset.type==='cashier'));document.getElementById('zoneModal').classList.add('open')}
function editZone(id){const z=INV.zones.find(x=>x.id==id);if(!z)return;INV.zm={id:z.id,name:z.name,type:z.zone_type,photo:z.photo_url,ctx:'hub'};document.getElementById('zmTitle').textContent='Редактирай място';document.getElementById('zmNameInput').value=z.name;if(z.photo_url){document.getElementById('zmPhotoImg').src=z.photo_url;document.getElementById('zmPhotoImg').style.display='block';document.getElementById('zmPhotoLabel').textContent=''}else{document.getElementById('zmPhotoImg').style.display='none';document.getElementById('zmPhotoLabel').textContent='Добави снимка'}document.querySelectorAll('.zt-tab').forEach(t=>t.classList.toggle('active',t.dataset.type===z.zone_type));document.getElementById('zoneModal').classList.add('open')}
function closeZoneModal(){document.getElementById('zoneModal').classList.remove('open')}
function selZoneType(t,el){INV.zm.type=t;document.querySelectorAll('.zt-tab').forEach(b=>b.classList.remove('active'));el.classList.add('active')}
// PHOTO
function openZoneCamera(){document.getElementById('zoneModal').style.display='none';if(navigator.mediaDevices&&navigator.mediaDevices.getUserMedia){navigator.mediaDevices.getUserMedia({video:{facingMode:'environment',width:{ideal:1280}}}).then(s=>{INV.cameraStream=s;document.getElementById('camVideo').srcObject=s;document.getElementById('cameraOv').classList.add('open')}).catch(()=>document.getElementById('zmGalleryInput').click())}else document.getElementById('zmGalleryInput').click()}
function closeCamera(){document.getElementById('cameraOv').classList.remove('open');document.getElementById('zoneModal').style.display='';if(INV.cameraStream){INV.cameraStream.getTracks().forEach(t=>t.stop());INV.cameraStream=null}}
async function captureZonePhoto(){const v=document.getElementById('camVideo'),c=document.getElementById('camCanvas');c.width=v.videoWidth;c.height=v.videoHeight;c.getContext('2d').drawImage(v,0,0);closeCamera();c.toBlob(async b=>{if(!b){toast('Грешка','err');return}const fd=new FormData();fd.append('photo',b,'zone.jpg');toast('Качвам...');const d=await fetch('inventory.php?ajax=upload_zone_photo',{method:'POST',body:fd}).then(r=>r.json());if(!d.ok){toast(d.error||'Грешка','err');return}applyPhotoToModal(d.url)},'image/jpeg',0.85)}
function addPhotoToZone(zId){document.getElementById('zmGalleryInput').dataset.direct=zId;document.getElementById('zmGalleryInput').click()}
async function handlePhotoUpload(inp){const f=inp.files[0];if(!f)return;const fd=new FormData();fd.append('photo',f);toast('Качвам...');const d=await fetch('inventory.php?ajax=upload_zone_photo',{method:'POST',body:fd}).then(r=>r.json());inp.value='';if(!d.ok){toast(d.error||'Грешка','err');return}if(inp.dataset.direct){const z=parseInt(inp.dataset.direct);inp.dataset.direct='';await api('update_zone_photo',{id:z,photo_url:d.url},'POST');const zn=INV.zones.find(x=>x.id===z);if(zn)zn.photo_url=d.url;document.getElementById('screen-hub').classList.contains('active')?renderHubZones():renderOnbZones();toast('Снимката е качена','ok');return}applyPhotoToModal(d.url)}
function applyPhotoToModal(url){INV.zm.photo=url;document.getElementById('zmPhotoImg').src=url;document.getElementById('zmPhotoImg').style.display='block';document.getElementById('zmPhotoLabel').textContent='';toast('Снимката е качена','ok')}
async function saveZone(){const nm=INV.zm.name||document.getElementById('zmNameInput').value.trim();INV.zm.name=nm;if(!nm){toast('Кажи или напиши името','err');return}const ep=INV.zm.id>0?INV.zones.find(z=>z.id===INV.zm.id)?.photo_url:null;try{const r=await api('save_zone',{id:INV.zm.id,name:nm,zone_type:INV.zm.type||'other',photo_url:INV.zm.photo||ep||null,sort_order:INV.zones.length},'POST');if(!r.ok){toast(r.error||'Грешка','err');return}closeZoneModal();toast('Запазено','ok');await loadZones();document.getElementById('screen-hub').classList.contains('active')?renderHubZones():renderOnbZones()}catch(e){toast('Грешка','err')}}
async function delZone(id){if(!confirm('Изтрий?'))return;await api('delete_zone',{id},'POST');INV.zones=INV.zones.filter(z=>z.id!==id);document.getElementById('screen-hub').classList.contains('active')?renderHubZones():renderOnbZones();toast('Изтрито')}
// VOICE
let _rec=null,_recCb=null;
function startVoice(cb,label){_recCb=cb;const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){toast('Гласът не се поддържа');return}_rec=new SR();_rec.lang='bg-BG';_rec.continuous=false;_rec.interimResults=true;document.getElementById('recOv').classList.add('active');document.getElementById('recDot').classList.remove('done');document.getElementById('recLbl').textContent=label||'ЗАПИСВА...';document.getElementById('recTrans').textContent='';document.getElementById('recSendBtn').style.display='none';_rec.onresult=e=>{let t='';for(let i=0;i<e.results.length;i++)t+=e.results[i][0].transcript;document.getElementById('recTrans').textContent=t;if(e.results[e.results.length-1].isFinal){document.getElementById('recDot').classList.add('done');document.getElementById('recLbl').textContent='ГОТОВО';document.getElementById('recSendBtn').style.display='block'}};_rec.onerror=()=>{document.getElementById('recOv').classList.remove('active');toast('Грешка с микрофона')};_rec.start()}
function recSend(){const t=document.getElementById('recTrans').textContent.trim();document.getElementById('recOv').classList.remove('active');if(_recCb&&t)_recCb(t)}
function recCancel(){if(_rec)try{_rec.stop()}catch(e){};document.getElementById('recOv').classList.remove('active')}
function startZoneVoice(){startVoice(t=>{INV.zm.name=t;document.getElementById('zmNameInput').value=t},'КАЗВАЙ ИМЕТО...')}
// INFO
const INFO={hub:{title:'Скрити пари',body:'Системата следи колко стока имаш. Всеки преброен артикул увеличава точността на AI.'},zones:{title:'Места в магазина',body:'<strong>Защо снимки?</strong> AI помни как изглежда всяко място.<br><br><strong>Примери:</strong> Щендер до входа, Рафт зад касата, Витрина дясна, Склад рафт 1...'}};
function showInfo(k){const c=INFO[k];if(!c)return;document.getElementById('infoTitle').textContent=c.title;document.getElementById('infoBody').innerHTML=c.body;document.getElementById('infoModal').classList.add('open')}
// HELPERS
function ztLabel(t){return{cashier:'Касова зона',customer:'Зона клиенти',storage:'Складово помещение',shop:'Магазин',other:'Друго'}[t]||t}
function esc(s){if(!s)return'';return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')}
function fmtPrice(v){if(!v)return'0,00 <?=$currency?>';return parseFloat(v).toFixed(2).replace('.',',')+' <?=$currency?>'}
async function api(ep,body,method){if(!method||method==='GET')return fetch(`inventory.php?ajax=${ep}`).then(r=>r.json());return fetch(`inventory.php?ajax=${ep}`,{method,headers:{'Content-Type':'application/json'},body:JSON.stringify(body)}).then(r=>r.json())}
function toast(msg,type){const t=document.getElementById('iToast');t.textContent=msg;t.className='inv-toast show'+(type?' '+type:'');clearTimeout(t._t);t._t=setTimeout(()=>t.classList.remove('show'),2500)}
</script></body></html>
